  return <Sidebar.Root>
      <Sidebar.SidePanel bg="bg.panel">
        <Sidebar.Header>
          <DocumentMenuButton />
        </Sidebar.Header>

        <Sidebar.Content>
          <Sidebar.Group>
            <Sidebar.GroupLabel>Get Started</Sidebar.GroupLabel>
            <Sidebar.GroupContent>
              <Sidebar.Item label="Installation" value="/get-started/installation" />

              <Sidebar.Item label="Frameworks" value="/get-started/frameworks">
                <Sidebar.Item label="Next.js (App)" value="/get-started/frameworks/nextjs-app" />
                <Sidebar.Item label="Next.js (Pages)" value="/get-started/frameworks/nextjs-pages" />
                <Sidebar.Item label="Vite" value="/get-started/frameworks/vite" />
                <Sidebar.Item label="React Router" value="/get-started/frameworks/react-router" />
                <Sidebar.Item label="TanStack Start" value="/get-started/frameworks/tanstack-start" />
                <Sidebar.Item label="TanStack Router" value="/get-started/frameworks/tanstack-router" />
              </Sidebar.Item>
            </Sidebar.GroupContent>
          </Sidebar.Group>

          <Sidebar.Group>
            <Sidebar.GroupLabel>Styling</Sidebar.GroupLabel>
            <Sidebar.GroupContent>
              <Sidebar.Item label="Overview" value="/styling/overview" />
              <Sidebar.Item label="Style Props" value="/styling/style-props" />
            </Sidebar.GroupContent>
          </Sidebar.Group>

          <Sidebar.Group>
            <Sidebar.GroupLabel>Theming</Sidebar.GroupLabel>
            <Sidebar.GroupContent>
              <Sidebar.Item label="Overview" value="/theming/overview" />
              <Sidebar.Item label="Customization" value="/theming/customization" />
            </Sidebar.GroupContent>
          </Sidebar.Group>
        </Sidebar.Content>

        <Sidebar.Footer>
          <UserMenuButton />
        </Sidebar.Footer>
      </Sidebar.SidePanel>

      <Sidebar.MainPanel p="md">
        <Sidebar.Trigger>
          <IconButton size="xs" variant="ghost" fontSize="md" icon={<PanelLeftIcon />} />
        </Sidebar.Trigger>
      </Sidebar.MainPanel>
    </Sidebar.Root>;
